const binary = await this.helpers.getBinaryDataBuffer(0, "data");
const base64 = binary.toString("base64");
const contexto = $("Preparar Contexto").item.json;
const mediaResolvida = $("Graph API - Resolver URL da Mídia").item.json;
const mimeType = contexto.media_mime_type || mediaResolvida.mime_type || "application/octet-stream";

return {
  json: {
    base64_data: base64,
    media_mime_type: mimeType,
    system_prompt: contexto.system_prompt,
    media_caption: contexto.media_caption,
  },
};

const response = $input.item.json;

// Gemini retorna em candidates[0].content.parts[0].text
const content = (
  response?.candidates?.[0]?.content?.parts?.[0]?.text ||
  response?.choices?.[0]?.message?.content ||
  ""
);

// Limpa escapes que o Gemini às vezes adiciona
const cleaned = content
  .replace(/\\n/g, '\n')
  .replace(/\\"/g, '"')
  .replace(/\\\\/g, '\\');

const match = cleaned.match(/<expense>([\s\S]*?)<\/expense>/);

if (!match) {
  throw new Error(`Resposta da IA nao contem bloco <expense>...</expense>: ${cleaned.substring(0, 200)}`);
}

let expenseJson;
try {
  expenseJson = JSON.parse(match[1].trim());
} catch (e) {
  throw new Error(`JSON invalido dentro do bloco expense: ${e.message}\nConteudo: ${match[1].substring(0, 200)}`);
}

const mensagemUsuario = cleaned.split('<expense>')[0].trim();

return {
  json: {
    expense: expenseJson,
    mensagem_usuario: mensagemUsuario || expenseJson.mensagem_usuario,
    session_id: $('Preparar Contexto').item.json.session_id,
    wa_id: $('Preparar Contexto').item.json.wa_id,
    phone: $('Preparar Contexto').item.json.phone,
  }
};

const contexto = $("Preparar Contexto").item.json;
const parsed = $("Extrair Bloco Expense").item.json.expense;
const sessaoResp = $input.item.json;
const usuarioId = Array.isArray(sessaoResp) ? (sessaoResp[0] && sessaoResp[0].usuario_id) : (sessaoResp && sessaoResp.usuario_id);

if (!usuarioId) {
  throw new Error("Sessao " + contexto.session_id + " ainda nao tem usuario_id vinculado (onboarding pendente)");
}

const status = parsed.requer_revisao_humana ? "REVISAO_HUMANA" : "RECEBIDO";

return {
  json: {
    usuario_id: usuarioId,
    sessao_whatsapp_id: contexto.session_id,
    origem: contexto.origem,
    status,
    descricao: parsed.descricao,
    estabelecimento: parsed.estabelecimento || null,
    documento_prestador: parsed.documento_prestador || null,
    data_despesa: parsed.data_despesa || null,
    valor: parsed.valor,
    categoria: parsed.categoria,
    deducibilidade: parsed.deducibilidade,
    justificativa_deducibilidade: parsed.justificativa_deducibilidade || null,
    confidence_score: parsed.confidence_score,
    requer_revisao_humana: parsed.requer_revisao_humana,
    possui_indicio_tuss_cbhpm: parsed.possui_indicio_tuss_cbhpm || false,
    codigos_medicos_identificados: parsed.codigos_medicos_identificados || [],
    termos_auditoria_identificados: parsed.termos_auditoria_identificados || [],
    arquivo_hash_sha256: contexto.media_sha256 || null,
    metadados_ia: parsed,
    mensagem_usuario: $("Extrair Bloco Expense").item.json.mensagem_usuario,
    wa_id: contexto.wa_id,
  },
};
